/**
 * Represents the items which the [`data`](components/gantt/api/ganttprops#toc-data) property accepts.
 * The `data` has no strict type. However, to visualize it correctly,
 * use it in combination with the [`modelFields`](components/gantt/api/ganttprops#toc-modelfields) property.
 */
export type DataItem = any;
